import React from "react";
import { Swiper, SwiperSlide } from "swiper/react";
import "swiper/css";
import "swiper/css/effect-fade";
import "swiper/css/navigation";
import "swiper/css/pagination";
import "./ProductsDetails.css";
import { EffectFade, Navigation, Pagination, Autoplay } from "swiper/modules";
import { useParams } from "react-router-dom";
import Aos from "aos";
import "aos/dist/aos.css";
import { useEffect } from "react";

function ProductsDetails({ images }) {
  useEffect(() => {
    Aos.init({ duration: 2000 });
  }, []);
  const { ProductId } = useParams();

  return (
    <>
      <Swiper
        rewind={true}
        spaceBetween={30}
        effect={"fade"}
        navigation={true}
        autoplay={{
          delay: 2500,
        }}
        pagination={{
          clickable: true,
          type: "bullets",
        }}
        modules={[EffectFade, Navigation, Pagination, Autoplay]}
        className="mySwiper"
      >
        {images[ProductId].Images.map((image, index) => {
          return (
            <SwiperSlide key={index}>
              <img src={image.image}></img>
            </SwiperSlide>
          );
        })}
      </Swiper>
      <section className="products-details-section">
        <h1 data-aos="fade-up" data-aos-duration="1500">
          {images[ProductId].title}
        </h1>
        <p
          className="products-details-text-title"
          data-aos="fade-up"
          data-aos-duration="1500"
        >
          Product Description
        </p>
        <p
          className="products-details-text-info"
          data-aos="fade-up"
          data-aos-duration="1500"
        >
          {images[ProductId].description}
        </p>
        <p
          className="products-details-text-title"
          data-aos="fade-up"
          data-aos-duration="1500"
        >
          Product ingredients
        </p>
        <p
          className="products-details-text-info"
          data-aos="fade-up"
          data-aos-duration="1500"
        >
          {images[ProductId].ingredients}
        </p>
        <p
          className="products-details-text-title"
          data-aos="fade-up"
          data-aos-duration="1500"
        >
          Weight
        </p>
        <p
          className="products-details-text-info"
          data-aos="fade-up"
          data-aos-duration="1500"
        >
          {images[ProductId].weight}
        </p>
        <p
          className="products-details-text-title"
          data-aos="fade-up"
          data-aos-duration="1500"
        >
          Packing
        </p>
        <p
          className="products-details-text-info"
          data-aos="fade-up"
          data-aos-duration="1500"
        >
          {images[ProductId].packing}
        </p>
      </section>
    </>
  );
}

export default ProductsDetails;
